CREATE TABLE IF NOT EXISTS users(id INT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(120) NOT NULL,email VARCHAR(190) NOT NULL UNIQUE,password_hash VARCHAR(255) NOT NULL,active TINYINT(1) NOT NULL DEFAULT 1,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS roles(id INT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(50) NOT NULL UNIQUE,label VARCHAR(100) NOT NULL);
CREATE TABLE IF NOT EXISTS permissions(id INT AUTO_INCREMENT PRIMARY KEY,code VARCHAR(80) NOT NULL UNIQUE,label VARCHAR(120) NOT NULL);
CREATE TABLE IF NOT EXISTS user_roles(user_id INT NOT NULL,role_id INT NOT NULL,PRIMARY KEY(user_id,role_id),FOREIGN KEY(user_id) REFERENCES users(id) ON DELETE CASCADE,FOREIGN KEY(role_id) REFERENCES roles(id) ON DELETE CASCADE);
CREATE TABLE IF NOT EXISTS role_permissions(role_id INT NOT NULL,permission_id INT NOT NULL,PRIMARY KEY(role_id,permission_id),FOREIGN KEY(role_id) REFERENCES roles(id) ON DELETE CASCADE,FOREIGN KEY(permission_id) REFERENCES permissions(id) ON DELETE CASCADE);
INSERT IGNORE INTO roles(id,name,label) VALUES(1,'owner','Eigenaar'),(2,'admin','Administrator'),(3,'bookkeeper','Boekhouder'),(4,'employee','Medewerker'),(5,'readonly','Alleen lezen');
INSERT IGNORE INTO permissions(id,code,label) VALUES(1,'*','Alle rechten'),(2,'data.read','Gegevens bekijken'),(3,'data.write','Gegevens wijzigen'),(4,'users.manage','Gebruikers beheren');
INSERT IGNORE INTO role_permissions VALUES(1,1),(2,2),(2,3),(2,4),(3,2),(3,3),(4,2),(4,3),(5,2);
CREATE TABLE IF NOT EXISTS customers(id INT AUTO_INCREMENT PRIMARY KEY,customer_number VARCHAR(40),type ENUM('particulier','zakelijk') DEFAULT 'particulier',name VARCHAR(150),company_name VARCHAR(150),contact_person VARCHAR(150),street VARCHAR(180),postal_code VARCHAR(20),city VARCHAR(100),email VARCHAR(190),phone VARCHAR(60),kvk VARCHAR(30),vat_number VARCHAR(40),iban VARCHAR(40),payment_term INT DEFAULT 14,recurring TINYINT(1) DEFAULT 0,payment_behavior VARCHAR(50) DEFAULT 'normaal',notes TEXT,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS documents(id INT AUTO_INCREMENT PRIMARY KEY,type ENUM('offerte','factuur','werkbon','creditfactuur') NOT NULL,number VARCHAR(60) UNIQUE,customer_id INT NULL,issue_date DATE,due_date DATE,status VARCHAR(40) DEFAULT 'concept',subtotal DECIMAL(12,2) DEFAULT 0,vat_total DECIMAL(12,2) DEFAULT 0,total DECIMAL(12,2) DEFAULT 0,notes TEXT,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,FOREIGN KEY(customer_id) REFERENCES customers(id) ON DELETE SET NULL);
CREATE TABLE IF NOT EXISTS document_items(id INT AUTO_INCREMENT PRIMARY KEY,document_id INT NOT NULL,description VARCHAR(255),quantity DECIMAL(10,2) DEFAULT 1,unit VARCHAR(30) DEFAULT 'stuk',unit_price DECIMAL(12,2) DEFAULT 0,vat_rate DECIMAL(5,2) DEFAULT 21,total DECIMAL(12,2) DEFAULT 0,inventory_id INT NULL,FOREIGN KEY(document_id) REFERENCES documents(id) ON DELETE CASCADE);
CREATE TABLE IF NOT EXISTS inventory(id INT AUTO_INCREMENT PRIMARY KEY,sku VARCHAR(80),name VARCHAR(180) NOT NULL,category VARCHAR(100),unit VARCHAR(30) DEFAULT 'stuk',stock DECIMAL(12,2) DEFAULT 0,min_stock DECIMAL(12,2) DEFAULT 0,purchase_price DECIMAL(12,2) DEFAULT 0,sale_price DECIMAL(12,2) DEFAULT 0,supplier VARCHAR(160),location VARCHAR(120),created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS inventory_movements(id INT AUTO_INCREMENT PRIMARY KEY,inventory_id INT NOT NULL,movement_date DATETIME DEFAULT CURRENT_TIMESTAMP,quantity DECIMAL(12,2) NOT NULL,reason VARCHAR(120),reference VARCHAR(120),FOREIGN KEY(inventory_id) REFERENCES inventory(id) ON DELETE CASCADE);
CREATE TABLE IF NOT EXISTS vehicles(id INT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(120) NOT NULL,type ENUM('bedrijfsauto','priveauto') DEFAULT 'bedrijfsauto',license_plate VARCHAR(30),odometer INT DEFAULT 0,apk_date DATE,insurance_date DATE,notes TEXT,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS vehicle_costs(id INT AUTO_INCREMENT PRIMARY KEY,vehicle_id INT NOT NULL,cost_date DATE,type VARCHAR(80),amount DECIMAL(12,2),odometer INT,description TEXT,FOREIGN KEY(vehicle_id) REFERENCES vehicles(id) ON DELETE CASCADE);
CREATE TABLE IF NOT EXISTS time_entries(id INT AUTO_INCREMENT PRIMARY KEY,customer_id INT NULL,work_date DATE,start_time TIME,end_time TIME,break_minutes INT DEFAULT 0,hours DECIMAL(8,2) DEFAULT 0,description TEXT,billable TINYINT(1) DEFAULT 1,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(customer_id) REFERENCES customers(id) ON DELETE SET NULL);
CREATE TABLE IF NOT EXISTS expenses(id INT AUTO_INCREMENT PRIMARY KEY,expense_date DATE,category VARCHAR(80),supplier VARCHAR(160),description TEXT,amount_ex_vat DECIMAL(12,2) DEFAULT 0,vat_amount DECIMAL(12,2) DEFAULT 0,amount_inc_vat DECIMAL(12,2) DEFAULT 0,payment_method VARCHAR(50),receipt_path VARCHAR(255),created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS appointments(id INT AUTO_INCREMENT PRIMARY KEY,customer_id INT NULL,title VARCHAR(180) NOT NULL,start_at DATETIME,end_at DATETIME,status VARCHAR(40) DEFAULT 'gepland',location VARCHAR(180),notes TEXT,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(customer_id) REFERENCES customers(id) ON DELETE SET NULL);
CREATE TABLE IF NOT EXISTS settings(id INT AUTO_INCREMENT PRIMARY KEY,setting_key VARCHAR(100) NOT NULL UNIQUE,setting_value TEXT,updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP);
INSERT IGNORE INTO settings(setting_key,setting_value) VALUES('company_name','KlusHulp Noord'),('slogan','Betaalbaar • Betrouwbaar • Voor Iedereen'),('default_private_payment_term','14'),('default_business_payment_term','30');
